using System;
using System.Collections.Concurrent;
using System.Reflection;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static void DrainNotificationQueue()
        {
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
        }

        public static Department CreateDepartment(int id = 1, string name = "Engineering", decimal budget = 100000m, int? instructorId = null)
        {
            return new Department
            {
                DepartmentID = id,
                Name = name,
                Budget = budget,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = instructorId
            };
        }

        public static Student CreateStudent(string lastName = "Smith", string firstName = "John", DateTime? enrollmentDate = null)
        {
            return new Student
            {
                LastName = lastName,
                FirstMidName = firstName,
                EnrollmentDate = enrollmentDate ?? DateTime.Today
            };
        }

        public static Instructor CreateInstructor(string lastName = "Doe", string firstName = "Jane", DateTime? hireDate = null)
        {
            return new Instructor
            {
                LastName = lastName,
                FirstMidName = firstName,
                HireDate = hireDate ?? new DateTime(2015, 1, 1),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };
        }

        public static Course CreateCourse(int courseId = 1050, string title = "Chemistry", int credits = 3, int departmentId = 1)
        {
            return new Course
            {
                CourseID = courseId,
                Title = title,
                Credits = credits,
                DepartmentID = departmentId
            };
        }

        public static void SeedStudents(SchoolContext context, int count = 5)
        {
            for (int i = 1; i <= count; i++)
            {
                context.Students.Add(new Student
                {
                    LastName = $"Student{i}",
                    FirstMidName = $"First{i}",
                    EnrollmentDate = new DateTime(2020, 1, 1).AddMonths(i - 1)
                });
            }
            context.SaveChanges();
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndexAndTotalPages()
        {
            var items = new List<string> { "a", "b", "c" };

            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
            Assert.Equal(3, list.Count);
        }

        [Fact]
        public void Constructor_TotalPages_RoundsUp()
        {
            var items = new List<int> { 1 };

            var list = new PaginatedList<int>(items, 11, 1, 5);

            Assert.Equal(3, list.TotalPages); // ceil(11/5) = 3
