    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            TestHelpers.DrainNotificationQueue();
            _service = new NotificationService();
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_WithDisplayName_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Smith", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_EnqueuesNotification()
        {
            _service.SendNotification("Course", "42", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Course", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Contains("Course (ID: 42)", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_DequeusFIFO()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void GenerateMessage_Create_WithDisplayName()
        {
            _service.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.Equal("New Student 'John Smith' has been created", notification.Message);
        }

        [Fact]
        public void GenerateMessage_Update_WithDisplayName()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();

            Assert.Equal("Course 'Chemistry' has been updated", notification.Message);
        }

        [Fact]
        public void GenerateMessage_Delete_WithDisplayName()
        {
            _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
        }

        [Fact]
        public void GenerateMessage_Create_WithoutDisplayName()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.Equal("New Student (ID: 1) has been created", notification.Message);
        }

        [Fact]
        public void GenerateMessage_Update_WithoutDisplayName()
        {
            _service.SendNotification("Course", "42", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();

            Assert.Equal("Course (ID: 42) has been updated", notification.Message);
        }

        [Fact]
        public void GenerateMessage_Delete_WithoutDisplayName()
        {
            _service.SendNotification("Department", "5", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            Assert.Equal("Department (ID: 5) has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();

            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_SetsOperationAsString()
        {
            _service.SendNotification("Student", "1", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            Assert.Equal("DELETE", notification.Operation);
        }

        [Fact]
        public void SendNotification_MultipleNotifications_AllQueued()
        {
            for (int i = 0; i < 5; i++)
            {
                _service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            int count = 0;
            while (_service.ReceiveNotification() != null) count++;

            Assert.Equal(5, count);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_NullDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "99", null, EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.Contains("ID: 99", notification.Message);
        }

        [Fact]
        public void SendNotification_EmptyDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "99", "", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.Contains("ID: 99", notification.Message);
        }

        [Fact]
        public void SendNotification_WhitespaceDisplayName_UsesIdFormat()
        {
            _service.SendNotification("Student", "99", "   ", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.Contains("ID: 99", notification.Message);
        }
    }
}

