+using System;
+using System.Collections.Generic;
+using System.Linq;
+using ContosoUniversity;
+using Xunit;
+
+namespace ContosoUniversity.Tests.Models
+{
+    public class PaginatedListTests
+    {
+        [Fact]
+        public void Constructor_SetsPageIndexAndTotalPages()
+        {
+            var items = new List<string> { "a", "b", "c" };
+
+            var list = new PaginatedList<string>(items, 10, 2, 3);
+
+            Assert.Equal(2, list.PageIndex);
+            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
+            Assert.Equal(3, list.Count);
+        }
+
+        [Fact]
+        public void Constructor_TotalPages_RoundsUp()
+        {
+            var items = new List<int> { 1 };
+
+            var list = new PaginatedList<int>(items, 11, 1, 5);
+
+            Assert.Equal(3, list.TotalPages); // ceil(11/5) = 3
+        }
+
+        [Fact]
+        public void Constructor_SinglePage_TotalPagesIsOne()
+        {
+            var items = new List<int> { 1, 2, 3 };
+
+            var list = new PaginatedList<int>(items, 3, 1, 10);
+
+            Assert.Equal(1, list.TotalPages);
+        }
+
+        [Theory]
+        [InlineData(1, false)]
+        [InlineData(2, true)]
+        [InlineData(3, true)]
+        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
+        {
+            var list = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);
+            Assert.Equal(expected, list.HasPreviousPage);
+        }
+
+        [Theory]
+        [InlineData(1, 3, true)]
+        [InlineData(2, 3, true)]
+        [InlineData(3, 3, false)]
+        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
+        {
+            var list = new PaginatedList<int>(new List<int>(), totalPages * 10, pageIndex, 10);
+            Assert.Equal(expected, list.HasNextPage);
+        }
+
+        [Fact]
+        public void Create_ReturnsCorrectPage()
+        {
+            var source = Enumerable.Range(1, 25).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 2, 10);
+
+            Assert.Equal(2, result.PageIndex);
+            Assert.Equal(3, result.TotalPages);
+            Assert.Equal(10, result.Count);
+            Assert.Equal(11, result.First());
+            Assert.Equal(20, result.Last());
+        }
+
+        [Fact]
+        public void Create_FirstPage_ContainsFirstItems()
+        {
+            var source = Enumerable.Range(1, 15).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 1, 5);
+
+            Assert.Equal(1, result.PageIndex);
+            Assert.Equal(3, result.TotalPages);
+            Assert.Equal(5, result.Count);
+            Assert.Equal(1, result.First());
+        }
+
+        [Fact]
+        public void Create_LastPage_ContainsRemainingItems()
+        {
+            var source = Enumerable.Range(1, 12).AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 3, 5);
+
+            Assert.Equal(3, result.PageIndex);
+            Assert.Equal(3, result.TotalPages);
+            Assert.Equal(2, result.Count);
+            Assert.Equal(11, result.First());
+        }
+
+        [Fact]
+        public void Create_EmptySource_ReturnsEmptyList()
+        {
+            var source = Enumerable.Empty<int>().AsQueryable();
+
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            Assert.Empty(result);
+            Assert.Equal(0, result.TotalPages);
+        }
+
+        [Fact]
+        public void HasPreviousPage_FirstPage_ReturnsFalse()
+        {
+            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
+            Assert.False(list.HasPreviousPage);
+        }
+
+        [Fact]
+        public void HasNextPage_OnLastPage_ReturnsFalse()
+        {
+            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
+            Assert.False(list.HasNextPage);
+        }
+    }
+}
