using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
            _controller.Dispose();
            _context.Dispose();
        }

        private void SeedStudents()
        {
            _context.Students.Add(new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) });
            _context.Students.Add(new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2019, 9, 1) });
            _context.Students.Add(new Student { LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2021, 9, 1) });
            _context.Students.Add(new Student { LastName = "Zheng", FirstMidName = "Nino", EnrollmentDate = new DateTime(2018, 9, 1) });
            _context.SaveChanges();
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewResult()
        {
            SeedStudents();
            var result = _controller.Index(null, null, null, null);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAsc()
        {
            SeedStudents();
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDesc()
        {
            SeedStudents();
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal("Zheng", model.First().LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAsc()
        {
            SeedStudents();
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal("Zheng", model.First().LastName); // 2018 is earliest
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDesc()
        {
            SeedStudents();
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal("Barzdukas", model.First().LastName); // 2021 is latest
        }

        [Fact]
        public void Index_SearchString_FiltersStudents()
        {
            SeedStudents();
            var result = _controller.Index(null, null, "Alex", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersStudents()
        {
            SeedStudents();
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchStringResetsPage()
        {
            SeedStudents();
            _controller.Index(null, null, "Alex", 3);
            // When searchString is not null, page should be reset to 1
            // This is handled internally in the controller
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            SeedStudents();
            var result = _controller.Index(null, "Alonso", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagCurrentSort()
        {
            SeedStudents();
            _controller.Index("name_desc", null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.CurrentSort);
        }

        [Fact]
        public void Index_SetsViewBagNameSortParm()
        {
            SeedStudents();
            _controller.Index(null, null, null, null);
            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);

            _controller.Index("name_desc", null, null, null);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_SetsViewBagDateSortParm()
        {
            SeedStudents();
            _controller.Index(null, null, null, null);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);

            _controller.Index("Date", null, null, null);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_Pagination_Page1()
        {
            // Add more than 10 students
            for (int i = 0; i < 15; i++)
            {
                _context.Students.Add(new Student
                {
                    LastName = $"Student{i:D2}",
                    FirstMidName = $"First{i}",
                    EnrollmentDate = DateTime.Today
                });
            }
            _context.SaveChanges();

            var result = _controller.Index(null, null, null, 1) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal(10, model.Count);
            Assert.True(model.HasNextPage);
            Assert.False(model.HasPreviousPage);
        }

        [Fact]
        public void Index_Pagination_Page2()
        {
            for (int i = 0; i < 15; i++)
            {
                _context.Students.Add(new Student
                {
                    LastName = $"Student{i:D2}",
                    FirstMidName = $"First{i}",
                    EnrollmentDate = DateTime.Today
                });
            }
            _context.SaveChanges();

            var result = _controller.Index(null, null, null, 2) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal(5, model.Count);
            Assert.False(model.HasNextPage);
            Assert.True(model.HasPreviousPage);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Today,
                Enrollments = new List<Enrollment>()
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            var result = _controller.Details(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("Test", model.LastName);
        }

        [Fact]
        public void Details_ValidId_IncludesEnrollments()
        {
            var dept = TestHelpers.CreateDepartment();
            _context.Departments.Add(dept);

            var course = TestHelpers.CreateCourse(departmentId: dept.DepartmentID);
            _context.Courses.Add(course);

            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Today,
                Enrollments = new List<Enrollment>
                {
                    new Enrollment { CourseID = course.CourseID, Grade = Grade.A }
                }
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            var result = _controller.Details(student.ID) as ViewResult;
            var model = Assert.IsType<Student>(result.Model);

            Assert.Single(model.Enrollments);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewWithStudentDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "New",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidStudent_SavesInDatabase()
        {
            var student = new Student
            {
                LastName = "New",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            Assert.Single(_context.Students);
            Assert.Equal("New", _context.Students.First().LastName);
        }

        [Fact]
        public void Create_Post_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                LastName = "New",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_DateBefore1753_AddsModelError()
        {
            var student = new Student
            {
                LastName = "New",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_Post_SendsNotification()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            var notification = new Services.NotificationService().ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("CREATE", notification.Operation);
        }

        #endregion

        #region Edit Tests

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var student = TestHelpers.CreateStudent();
            _context.Students.Add(student);
            _context.SaveChanges();

            var result = _controller.Edit(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = TestHelpers.CreateStudent();
            _context.Students.Add(student);
            _context.SaveChanges();

            // Detach to simulate a form post
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editedStudent = new Student
            {
                ID = student.ID,
                LastName = "Updated",
                FirstMidName = "Name",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Edit(editedStudent);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
