using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _envMock;
        private readonly Mock<ILogger<CoursesController>> _loggerMock;

        public CoursesControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateInMemoryContext();
            _envMock = new Mock<IWebHostEnvironment>();
            _envMock.Setup(e => e.WebRootPath).Returns((string)null);
            _envMock.Setup(e => e.ContentRootPath).Returns(Path.Combine(Directory.GetCurrentDirectory(), "test_content"));
            _loggerMock = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
            _controller.Dispose();
            _context.Dispose();
            // Clean up test upload directories
            var testPath = Path.Combine(Directory.GetCurrentDirectory(), "test_content", "Uploads");
            if (Directory.Exists(testPath))
            {
                try { Directory.Delete(testPath, true); } catch { }
            }
        }

        private void SeedDepartmentAndCourse()
        {
            var dept = TestHelpers.CreateDepartment();
            _context.Departments.Add(dept);
            _context.SaveChanges();
        }

        private void SeedCourse(int courseId = 1050, string title = "Chemistry")
        {
            SeedDepartmentAndCourse();
            var course = TestHelpers.CreateCourse(courseId, title);
            _context.Courses.Add(course);
            _context.SaveChanges();
        }

        private Mock<IFormFile> CreateMockFile(string fileName = "test.jpg", long length = 1024)
        {
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.Length).Returns(length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));
            return fileMock;
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            SeedDepartmentAndCourse();
            var course = TestHelpers.CreateCourse();
            _context.Courses.Add(course);
            _context.SaveChanges();

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<List<Course>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_EmptyDatabase_ReturnsEmptyList()
        {
            var result = _controller.Index() as ViewResult;
            var model = Assert.IsType<List<Course>>(result.Model);
            Assert.Empty(model);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            SeedDepartmentAndCourse();
            var course = TestHelpers.CreateCourse();
            _context.Courses.Add(course);
            _context.SaveChanges();

            var result = _controller.Details(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        #endregion

        #region Create Tests

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentDropdown()
        {
            SeedDepartmentAndCourse();

            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_ValidCourse_NoFile_RedirectsToIndex()
        {
            SeedDepartmentAndCourse();
            var course = new Course
            {
                CourseID = 2000,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidCourse_SavesInDatabase()
        {
            SeedDepartmentAndCourse();
            var course = new Course
            {
                CourseID = 2000,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            _controller.Create(course, null);

            Assert.Equal(1, _context.Courses.Count());
        }

        [Fact]
        public void Create_Post_InvalidExtension_ReturnsViewWithError()
        {
            SeedDepartmentAndCourse();
            var course = new Course
            {
                CourseID = 2000,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };
            var fileMock = CreateMockFile("test.exe");

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_OversizedFile_ReturnsViewWithError()
        {
            SeedDepartmentAndCourse();
            var course = new Course
            {
                CourseID = 2000,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };
            var fileMock = CreateMockFile("test.jpg", 6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
