namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
        }

        public void Dispose()
        {
            TestHelpers.DrainNotificationQueue();
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.IsType<JsonResult>(result);
            dynamic value = result.Value;
            // Use reflection to verify properties
            var valueType = result.Value.GetType();
            var successProp = valueType.GetProperty("success");
            var countProp = valueType.GetProperty("count");

            Assert.True((bool)successProp.GetValue(result.Value));
            Assert.Equal(0, (int)countProp.GetValue(result.Value));
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            var service = new NotificationService();
            service.SendNotification("Student", "1", "John", EntityOperation.CREATE);
            service.SendNotification("Course", "2", "Math", EntityOperation.UPDATE);

            var result = _controller.GetNotifications();

            var valueType = result.Value.GetType();
            var successProp = valueType.GetProperty("success");
            var countProp = valueType.GetProperty("count");
            var notificationsProp = valueType.GetProperty("notifications");

            Assert.True((bool)successProp.GetValue(result.Value));
            Assert.Equal(2, (int)countProp.GetValue(result.Value));
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();

            var valueType = result.Value.GetType();
            var countProp = valueType.GetProperty("count");

            Assert.Equal(10, (int)countProp.GetValue(result.Value));
        }

        [Fact]
        public void GetNotifications_DequuesNotifications()
        {
            var service = new NotificationService();
            service.SendNotification("Student", "1", EntityOperation.CREATE);

            _controller.GetNotifications();

            // Queue should be empty now
            Assert.Null(service.ReceiveNotification());
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.IsType<JsonResult>(result);
            var valueType = result.Value.GetType();
            var successProp = valueType.GetProperty("success");
            Assert.True((bool)successProp.GetValue(result.Value));
        }

        [Fact]
        public void GetNotifications_MultipleCalls_DrainQueue()
        {
            var service = new NotificationService();
            for (int i = 0; i < 3; i++)
            {
                service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            var firstResult = _controller.GetNotifications();
            var secondResult = _controller.GetNotifications();

            var valueType = secondResult.Value.GetType();
            var countProp = valueType.GetProperty("count");
            Assert.Equal(0, (int)countProp.GetValue(secondResult.Value));
        }
    }
}

